2	  private static readonly LEFT_TURNS: Record<string, string> = {
3	    N: "W",
4	    W: "S",
5	    S: "E",
6	    E: "N",
7	  };
8	
9	  private static readonly RIGHT_TURNS: Record<string, string> = {
10	    N: "E",
11	    E: "S",
12	    S: "W",
13	    W: "N",
14	  };
15	
16	  private static readonly MOVEMENT_DELTAS: Record<string, { dx: number; dy: number }> = {
17	    N: { dx: 0, dy: 1 },
18	    E: { dx: 1, dy: 0 },
19	    S: { dx: 0, dy: -1 },
20	    W: { dx: -1, dy: 0 },
21	  };
22	
23	  constructor(
24	    public x: number,
25	    public y: number,
26	    public heading: string,
27	  ) {}
28	
29	  rotateLeft(): void {
30	    const newHeading = MarsRover.LEFT_TURNS[this.heading];
31	    if (newHeading) {
32	      this.heading = newHeading;
33	    }
34	  }
35	
36	  rotateRight(): void {
37	    const newHeading = MarsRover.RIGHT_TURNS[this.heading];
38	    if (newHeading) {
39	      this.heading = newHeading;
40	    }
41	  }
42	
43	  moveForward(): void {
44	    const delta = MarsRover.MOVEMENT_DELTAS[this.heading];
45	    if (delta) {
46	      this.x += delta.dx;
47	      this.y += delta.dy;
48	    }
49	  }
50	
